
INSERT INTO public.reviews (college_id, college_name, author_name, course, rating, body, status, created_at)
SELECT c.id, c.name, v.author_name, v.course, v.rating, v.body, 'approved'::review_status, v.created_at::timestamptz
FROM (VALUES
  ('acharya-narendra-dev-college','Vaibhav Rastogi','BSc Computer Science',4.5,'ANDC has a surprisingly strong CS department. Labs are decent and the seniors are very helpful with internship referrals. Kalkaji metro right next door is a big plus.','2026-06-12 10:30:00+00'),
  ('acharya-narendra-dev-college','Pooja Rathore','BSc Biomedical Science',4.3,'Biomedical course at ANDC is one of the few in DU. Faculty genuinely cares and the practical exposure is good for a south campus college.','2026-03-18 12:10:00+00'),
  ('aryabhatta-college','Karan Sehgal','BMS',4.4,'Aryabhatta is quietly building a name in management. The BMS batch is small so you actually get attention from professors. Decent placement support too.','2026-05-04 09:20:00+00'),
  ('aryabhatta-college','Divya Saxena','BA Economics Hons',4.2,'Campus is compact but the economics department punches above its weight. Guest lectures from DSE alumni were the highlight of my year.','2026-02-09 16:00:00+00'),
  ('bhaskaracharya-college-of-applied-sciences','Aniket Joshi','BSc Instrumentation',4.6,'Bhaskaracharya is the place if you actually like applied sciences. Instrumentation lab equipment is genuinely better than most DU colleges. Niche but rewarding.','2026-05-22 11:45:00+00'),
  ('bhaskaracharya-college-of-applied-sciences','Simran Kohli','BSc Food Technology',4.4,'Food tech program is unique and the industry visits we got were excellent. Dwarka location is a bit far but the course makes up for it.','2026-01-30 14:25:00+00'),
  ('college-of-vocational-studies','Rachit Bhalla','BMS',4.3,'CVS has improved a lot recently. Placement cell is actually proactive and the management courses feel updated. South campus crowd is fun.','2026-04-17 10:00:00+00'),
  ('college-of-vocational-studies','Anushka Pillai','BA Office Management and Secretarial Practice',4.1,'Unusual course but CVS handles it well. Small classes mean professors remember your name. Triveni canteen is a vibe.','2025-11-30 13:15:00+00'),
  ('deen-dayal-upadhyaya-college','Parth Anand','BSc Computer Science',4.6,'DDUC has the best CS curriculum in west campus IMO. Coding culture among students is strong and the placement numbers keep getting better each year.','2026-06-05 09:50:00+00'),
  ('deen-dayal-upadhyaya-college','Bhavya Sirohi','BSc Mathematics',4.4,'Math department here is solid. Profs go beyond syllabus and there is a real research-mindedness which is rare in DU undergrad.','2026-02-22 15:40:00+00'),
  ('deshbandhu-college','Mayank Tomar','BCom',4.2,'DBC is underrated honestly. Quiet campus, supportive teachers, and Kalkaji metro right outside. Good for students who want focus over hype.','2026-05-10 11:30:00+00'),
  ('deshbandhu-college','Ritika Bhatt','BSc Zoology',4.3,'Zoology lab is genuinely well stocked and the field trips were memorable. Faculty is approachable and grading is fair.','2026-01-15 10:20:00+00'),
  ('dyal-singh-college','Saurabh Pandey','BA Programme',4.0,'Dyal Singh has a mixed bag of teachers but the ones who are good are really good. Lodhi Road location is unbeatable for internships.','2026-04-28 14:10:00+00'),
  ('dyal-singh-college','Aishwarya Mehta','BA Journalism',4.2,'Journalism dept has working journalists as guest faculty which makes a huge difference. Campus is small but central.','2025-12-19 16:50:00+00'),
  ('indraprastha-college-for-women','Tanisha Goel','BA Psychology',4.7,'IP College has the kind of legacy you feel walking in. Psych dept is fantastic and the society culture pushes you to grow fast.','2026-06-01 12:00:00+00'),
  ('indraprastha-college-for-women','Avani Kashyap','BA English Hons',4.6,'Oldest women college in India and you can feel the depth in literature classes. Shakespeare Society events are legendary.','2026-03-08 11:20:00+00'),
  ('jesus-and-mary-college','Kritika Dsouza','BA Economics',4.7,'JMC is calm, disciplined and academically very strong. Chanakyapuri location is gorgeous and the eco department is one of the best.','2026-05-26 10:15:00+00'),
  ('jesus-and-mary-college','Naina Fernandes','BA Psychology',4.6,'Small batches, attentive faculty and a really respectful campus culture. Montage fest is criminally underrated.','2026-02-14 13:30:00+00'),
  ('kalindi-college','Bhumika Chopra','BCom',4.1,'Kalindi is no-frills but the teaching is sincere. East Patel Nagar metro stop is close which makes commute easy.','2026-04-09 09:45:00+00'),
  ('kalindi-college','Ridhi Tandon','BA Hindi Hons',4.2,'Hindi department here is genuinely passionate. If you love literature in its native language, you will feel at home.','2025-12-05 15:10:00+00'),
  ('kamla-nehru-college','Aastha Bedi','BA Political Science',4.4,'KNC is in the heart of south campus and the political science discussions in class are genuinely sharp. Ullas fest is fun.','2026-05-18 11:55:00+00'),
  ('kamla-nehru-college','Jiya Sondhi','BCom Hons',4.3,'Commerce dept is solid and placements have improved noticeably. Faculty actually answers emails which sounds basic but matters.','2026-01-25 14:40:00+00'),
  ('lady-shri-ram-college-for-women','Anvita Reddy','BA Economics Hons',4.9,'LSR genuinely changes how you think. The eco dept is brutal but you come out of it sharper than you ever imagined. Tarang is iconic.','2026-06-15 10:05:00+00'),
  ('lady-shri-ram-college-for-women','Saanvi Iyer','BA Sociology',4.8,'Society culture at LSR is unmatched. Every class feels like a real debate. The crowd you study with will push you for life.','2026-03-22 12:25:00+00'),
  ('mata-sundri-college-for-women','Gurleen Kaur','BCom',4.3,'MSCW has a very warm community and the commerce faculty is patient. ITO location is a huge plus for internships.','2026-04-25 13:50:00+00'),
  ('mata-sundri-college-for-women','Harnoor Sandhu','BA Economics',4.2,'Small but tight knit campus. Teachers actually know your name by the second week. Great for focused students.','2025-12-28 09:35:00+00'),
  ('motilal-nehru-college','Rajat Solanki','BCom',4.2,'MLNC main campus is decent and the placement cell genuinely tries. Benito Juarez metro nearby makes life easy.','2026-05-30 11:10:00+00'),
  ('motilal-nehru-college','Pranjal Negi','BSc Computer Science',4.4,'CS dept here is improving fast. Coding club is active and seniors share interview prep generously.','2026-02-05 16:15:00+00'),
  ('pgdav-college','Yashvi Aggarwal','BCom Hons',4.4,'PGDAV is honestly one of the most underrated commerce colleges. CA aspirants find a strong peer group here. Nehru Nagar campus is calm.','2026-06-08 10:40:00+00'),
  ('pgdav-college','Ishaan Khurana','BA Economics',4.3,'Profs in economics know their stuff and the library has the books you actually need. Solid choice for serious students.','2026-03-12 14:00:00+00'),
  ('shaheed-bhagat-singh-college','Dev Chaudhary','BCom Hons',4.3,'SBSC has a chill but academically focused vibe. South campus area is great and the placement cell is improving year over year.','2026-04-20 12:30:00+00'),
  ('shaheed-bhagat-singh-college','Meher Walia','BA Economics',4.2,'Faculty is approachable and the economics dept arranges good guest lectures. Small enough that you actually participate in class.','2025-11-15 10:55:00+00'),
  ('shri-ram-college-of-commerce','Vihaan Bansal','BA Economics Hons',4.9,'SRCC eco is a different animal. The curriculum is rigorous and the peer learning alone is worth the entire degree. Crossroads is the best fest in DU.','2026-06-18 09:25:00+00'),
  ('shri-ram-college-of-commerce','Aarohi Mittal','BCom Hons',4.8,'SRCC opens doors but you have to earn them. Recruitment season is intense and the alumni network is genuinely the strongest in DU commerce.','2026-03-28 11:35:00+00'),
  ('st-stephens-college','Reyansh Mathew','BA Economics',4.8,'Stephens has its own ecosystem. Tutorials, residency, the chapel culture, the lawns — nothing else in DU comes close to this experience.','2026-06-20 10:50:00+00'),
  ('st-stephens-college','Anaisha Thomas','BA English Hons',4.7,'English dept at Stephens is genuinely world class. The tutorial system means real one-on-one engagement with profs. Harmony is special.','2026-04-05 13:40:00+00'),
  ('zakir-husain-delhi-college','Faizan Ahmed','BA History',4.1,'ZHDC heritage campus is unlike anything else in DU. History department in a 17th century building hits different. Faculty has gems.','2026-05-14 12:15:00+00'),
  ('zakir-husain-delhi-college','Saba Qureshi','BA Urdu',4.3,'Urdu department here is one of the finest in the country. If you love the language, you will not find a better place to study it.','2026-02-01 15:25:00+00')
) AS v(slug, author_name, course, rating, body, created_at)
JOIN public.colleges c ON c.slug = v.slug;
